import request from '@/utils/request';
export default {
  getList: function getList(params) {
    return request({
      url: '/role/list',
      method: 'get',
      params: params
    });
  },
  save: function save(params) {
    return request({
      url: '/role',
      method: 'post',
      data: params
    });
  },
  remove: function remove(roleId) {
    return request({
      url: '/role',
      method: 'delete',
      params: {
        roleId: roleId
      }
    });
  },
  roleTreeListByIdUser: function roleTreeListByIdUser(idUser) {
    return request({
      url: '/role/roleTreeListByIdUser',
      method: 'get',
      params: {
        idUser: idUser
      }
    });
  },
  savePermissons: function savePermissons(params) {
    return request({
      url: '/role/savePermisson',
      method: 'post',
      params: params
    });
  }
};
